3027           if (DemandedMask & fcNegFinite)
3028             SrcDemandedMask |= fcNegFinite;
3029           if (DemandedMask & fcPosFinite)
3030             SrcDemandedMask |= fcPosFinite;
3031           if (DemandedMask & fcPosInf)
3032             SrcDemandedMask |= fcPosInf;
3033           if (DemandedMask & fcNegInf)
3034             SrcDemandedMask |= fcNegInf;
3035 
3036           KnownFPClass KnownSrc;
3037           if (SimplifyDemandedFPClass(II, 0, SrcDemandedMask, KnownSrc,
3038                                       Depth + 1))
3039             return I;
3040 
3041           Type *EltTy = VTy->getScalarType();
3042           DenormalMode Mode = F.getDenormalMode(EltTy->getFltSemantics());
3043 
3044           Known = KnownFPClass::frexp_mant(KnownSrc, Mode);
3045           Known.KnownFPClasses &= DemandedMask;
3046 
3047           if (Constant *SingleVal =
3048                   getFPClassConstant(VTy, Known.KnownFPClasses,
3049                                      /*IsCanonicalizing=*/true))
3050             return SingleVal;
