3072 /// Helper routine of SimplifyDemandedUseFPClass. It computes Known
3073 /// floating-point classes. It also tries to handle simplifications that can be
3074 /// done based on DemandedMask, but without modifying the Instruction.
3075 Value *InstCombinerImpl::SimplifyMultipleUseDemandedFPClass(
3076     Instruction *I, FPClassTest DemandedMask, KnownFPClass &Known,
3077     Instruction *CxtI, unsigned Depth) {
3078   FastMathFlags FMF;
3079   if (auto *FPOp = dyn_cast<FPMathOperator>(I)) {
3080     FMF = FPOp->getFastMathFlags();
3081     DemandedMask = adjustDemandedMaskFromFlags(DemandedMask, FMF);
3082   }
3083 
3084   // Remove unwanted results from the computed result
3085   scope_exit ApplyDemandedMask(
3086       [=, &Known]() { Known.knownNot(~DemandedMask); });
3087 
3088   switch (I->getOpcode()) {
3089   case Instruction::Select: {
3090     // TODO: Can we infer which side it came from based on adjusted result
3091     // class?
3092     KnownFPClass KnownRHS =
3093         computeKnownFPClass(I->getOperand(2), DemandedMask, CxtI, Depth + 1);
3094     if (KnownRHS.isKnownNever(DemandedMask))
3095       return I->getOperand(1);
3096 
3097     KnownFPClass KnownLHS =
3098         computeKnownFPClass(I->getOperand(1), DemandedMask, CxtI, Depth + 1);
3099     if (KnownLHS.isKnownNever(DemandedMask))
3100       return I->getOperand(2);
3101 
3102     adjustKnownFPClassForSelectArm(KnownLHS, I->getOperand(0), I->getOperand(1),
3103                                    /*Invert=*/false, SQ, Depth);
3104     adjustKnownFPClassForSelectArm(KnownRHS, I->getOperand(0), I->getOperand(2),
3105                                    /*Invert=*/true, SQ, Depth);
3106     Known = KnownLHS.intersectWith(KnownRHS);
3107     break;
3108   }
3109   case Instruction::FNeg: {
3110     // Special case fneg(fabs(x))
3111     Value *Src;
3112 
3113     Value *FNegSrc = I->getOperand(0);
3114     if (!match(FNegSrc, m_FAbs(m_Value(Src)))) {
3115       Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3116       break;
3117     }
3118 
3119     FastMathFlags FabsFMF = cast<FPMathOperator>(FNegSrc)->getFastMathFlags();
3120     FPClassTest ThisDemandedMask =
3121         adjustDemandedMaskFromFlags(DemandedMask, FabsFMF);
3122 
3123     KnownFPClass KnownSrc =
3124         computeKnownFPClass(Src, fcAllFlags, CxtI, Depth + 1);
3125 
3126     if ((ThisDemandedMask & fcNan) == fcNone)
3127       KnownSrc.knownNot(fcNan);
3128     if ((ThisDemandedMask & fcInf) == fcNone)
3129       KnownSrc.knownNot(fcInf);
3130 
3131     // If the source value is known negative, we can directly fold to it.
3132     if (KnownSrc.SignBit == true)
3133       return Src;
3134 
3135     // If the only sign bit difference is for 0, ignore it with nsz.
3136     if ((FMF.noSignedZeros() || FabsFMF.noSignedZeros()) &&
3137         KnownSrc.isKnownNever(KnownFPClass::OrderedGreaterThanZeroMask | fcNan))
3138       return Src;
3139 
3140     Known = KnownFPClass::fneg(KnownFPClass::fabs(KnownSrc));
3141     break;
3142   }
3143   case Instruction::Call: {
3144     const CallInst *CI = cast<CallInst>(I);
3145     const Intrinsic::ID IID = CI->getIntrinsicID();
3146     switch (IID) {
3147     case Intrinsic::fabs: {
3148       Value *Src = CI->getArgOperand(0);
3149       KnownFPClass KnownSrc =
3150           computeKnownFPClass(Src, fcAllFlags, CxtI, Depth + 1);
3151 
3152       if (Value *Simplified = simplifyDemandedFPClassFabs(
3153               Known, CI->getArgOperand(0), DemandedMask, KnownSrc,
3154               FMF.noSignedZeros()))
3155         return Simplified;
3156       break;
3157     }
3158     case Intrinsic::maximum:
3159     case Intrinsic::minimum:
3160     case Intrinsic::maximumnum:
3161     case Intrinsic::minimumnum: {
3162       KnownFPClass KnownRHS = computeKnownFPClass(
3163           CI->getArgOperand(1), DemandedMask, CxtI, Depth + 1);
3164       if (KnownRHS.isUnknown())
3165         return nullptr;
3166 
3167       KnownFPClass KnownLHS = computeKnownFPClass(
3168           CI->getArgOperand(0), DemandedMask, CxtI, Depth + 1);
3169 
3170       return simplifyDemandedFPClassMinMax(
3171           Known, IID, CI, DemandedMask, KnownLHS, KnownRHS, F,
3172           cast<FPMathOperator>(CI)->hasNoSignedZeros());
3173     }
3174     default:
3175       break;
3176     }
3177 
3178     [[fallthrough]];
3179   }
3180   default:
3181     Known = computeKnownFPClass(I, DemandedMask, CxtI, Depth + 1);
3182     break;
3183   }
3184 
3185   return getFPClassConstant(I->getType(), DemandedMask & Known.KnownFPClasses);
3186 }
3187 
3188 bool InstCombinerImpl::SimplifyDemandedFPClass(Instruction *I, unsigned OpNo,
3189                                                FPClassTest DemandedMask,
3190                                                KnownFPClass &Known,
3191                                                unsigned Depth) {
3192   Use &U = I->getOperandUse(OpNo);
3193   Value *V = U.get();
3194   Type *VTy = V->getType();
3195 
3196   if (DemandedMask == fcNone) {
3197     if (isa<UndefValue>(V))
3198       return false;
3199     replaceUse(U, PoisonValue::get(VTy));
3200     return true;
3201   }
3202 
3203   // Handle constant
3204   Instruction *VInst = dyn_cast<Instruction>(V);
3205   if (!VInst) {
3206     // Handle constants and arguments
3207     Known = computeKnownFPClass(V, fcAllFlags, I, Depth);
3208     Known.knownNot(~DemandedMask);
3209 
3210     if (Known.KnownFPClasses == fcNone) {
3211       if (isa<UndefValue>(V))
3212         return false;
3213       replaceUse(U, PoisonValue::get(VTy));
3214       return true;
3215     }
3216 
3217     // Do not try to replace values which are already constants (unless we are
3218     // folding to poison). Doing so could promote poison elements to non-poison
3219     // constants.
3220     if (isa<Constant>(V))
3221       return false;
3222 
3223     Value *FoldedToConst = getFPClassConstant(VTy, Known.KnownFPClasses);
3224     if (!FoldedToConst || FoldedToConst == V)
3225       return false;
3226 
3227     replaceUse(U, FoldedToConst);
3228     return true;
3229   }
3230 
3231   if (Depth == MaxAnalysisRecursionDepth)
3232     return false;
3233 
3234   Value *NewVal;
3235 
3236   if (VInst->hasOneUse()) {
3237     // If the instruction has one use, we can directly simplify it.
3238     NewVal = SimplifyDemandedUseFPClass(VInst, DemandedMask, Known, I, Depth);
3239   } else {
3240     // If there are multiple uses of this instruction, then we can simplify
3241     // VInst to some other value, but not modify the instruction.
3242     NewVal = SimplifyMultipleUseDemandedFPClass(VInst, DemandedMask, Known, I,
3243                                                 Depth);
3244   }
3245 
3246   if (!NewVal)
3247     return false;
3248   if (Instruction *OpInst = dyn_cast<Instruction>(U))
3249     salvageDebugInfo(*OpInst);
3250 
3251   replaceUse(U, NewVal);
3252   return true;
3253 }
